const raw = $json.body ?? $json;
let data = raw;
if (typeof data === 'string') {
  try { data = JSON.parse(data); } catch (e) { data = {}; }
}
if (typeof data !== 'object' || data === null || Array.isArray(data)) { data = {}; }

const pick = (obj, keys, fallback) => {
  fallback = fallback === undefined ? '' : fallback;
  for (const key of keys) {
    const val = obj[key];
    if (val !== undefined && val !== null && String(val).trim() !== '') {
      return typeof val === 'string' ? val.trim() : String(val);
    }
  }
  return fallback;
};

const dateBR = new Date().toLocaleDateString('pt-BR', { timeZone: 'America/Sao_Paulo' });

const nome     = pick(data, ['nome', 'Nome completo'], '');
const email    = pick(data, ['email', 'E-mail'], '');
const wpp      = pick(data, ['whatsapp', 'WhatsApp'], '');
const wpp2     = pick(data, ['whatsapp_confirmacao', 'Confirmar WhatsApp'], '');
const pergAdic = pick(data, ['pergunta_adicional', 'Pergunta adicional', 'Pergunta Adicional'], '');

const channel  = pick(data, ['channel', 'canal'], 'direto');
const source   = pick(data, ['source', 'utm_source'], 'direto');
const medium   = pick(data, ['medium', 'utm_medium'], 'none');
const campaign = pick(data, ['campaign', 'utm_campaign'], 'none');
const content  = pick(data, ['utm_content', 'content'], 'none');
const referrer = pick(data, ['referrer'], '');
const pageUrl  = pick(data, ['page_url'], '');
const timestamp = pick(data, ['timestamp'], new Date().toISOString());
const mql       = pick(data, ['mql'], '');

return [{
  json: {
    'Entrada leads':            dateBR,
    'Data de entrada de leads': dateBR,
    'Nome completo':            nome,
    'E-mail':                   email,
    'WhatsApp':                 (wpp  ? wpp.replace(/^\+/,'') : ''),
    'Confirmar WhatsApp':       (wpp2 ? wpp2.replace(/^\+/,'') : ''),
    'Pergunta Adicional':       pergAdic,
    'Funil':                    'diagnostico-organico',
    channel,
    Channel:                    channel,
    Source:                     source,
    Medium:                     medium,
    Campaign:                   campaign,
    Content:                    content,
    Referrer:                   referrer,
    'Page URL':                 pageUrl,
    Timestamp:                  timestamp,
    'MQL':                      mql
  }
}];
